#include <bits/stdc++.h>
using namespace std;

const int N=3010;

int n,m,a[N][N];
bool b[N];

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++){
        int u,v;
        scanf("%d%d",&u,&v);
        a[u][v]=a[v][u]=1;
    }
    for(int i=1;i<=n;i++)
        for(int j=i+1;j<=n && !b[i];j++)
            if(!b[j] && !a[i][j])
                b[i]=b[j]=1;
    for(int i=1,cnt=n/3;cnt;i++)
        if(!b[i]){
            cnt--;
            printf("%d ",i);
        }
    return 0;
}
